class AllMethods extends OpenAccountMethods {}

/**
 * Gerador de QR Code PIX Estático em Node.js
 * Implementado para uso integrado com a classe EfiPay (sdk-node-apis-efi).
 *
 * Baseado na lógica do repositório:
 * https://github.com/NascentSecureTech/pix-qrcode-utils
 *
 * Retorna o mesmo formato do endpoint pixGenerateQRCode da API Efí:
 * { qrcode: string, imagemQrcode: string }
 */

// ============================================================
// 1. CRC-16 CCITT (polinômio 0x1021)
// ============================================================
const CRC_TABLE = [0x0000, 0x1021, 0x2042, 0x3063, 0x4084, 0x50a5, 0x60c6, 0x70e7, 0x8108, 0x9129, 0xa14a, 0xb16b, 0xc18c, 0xd1ad, 0xe1ce, 0xf1ef, 0x1231, 0x0210, 0x3273, 0x2252, 0x52b5, 0x4294, 0x72f7, 0x62d6, 0x9339, 0x8318, 0xb37b, 0xa35a, 0xd3bd, 0xc39c, 0xf3ff, 0xe3de, 0x2462, 0x3443, 0x0420, 0x1401, 0x64e6, 0x74c7, 0x44a4, 0x5485, 0xa56a, 0xb54b, 0x8528, 0x9509, 0xe5ee, 0xf5cf, 0xc5ac, 0xd58d, 0x3653, 0x2672, 0x1611, 0x0630, 0x76d7, 0x66f6, 0x5695, 0x46b4, 0xb75b, 0xa77a, 0x9719, 0x8738, 0xf7df, 0xe7fe, 0xd79d, 0xc7bc, 0x48c4, 0x58e5, 0x6886, 0x78a7, 0x0840, 0x1861, 0x2802, 0x3823, 0xc9cc, 0xd9ed, 0xe98e, 0xf9af, 0x8948, 0x9969, 0xa90a, 0xb92b, 0x5af5, 0x4ad4, 0x7ab7, 0x6a96, 0x1a71, 0x0a50, 0x3a33, 0x2a12, 0xdbfd, 0xcbdc, 0xfbbf, 0xeb9e, 0x9b79, 0x8b58, 0xbb3b, 0xab1a, 0x6ca6, 0x7c87, 0x4ce4, 0x5cc5, 0x2c22, 0x3c03, 0x0c60, 0x1c41, 0xedae, 0xfd8f, 0xcdec, 0xddcd, 0xad2a, 0xbd0b, 0x8d68, 0x9d49, 0x7e97, 0x6eb6, 0x5ed5, 0x4ef4, 0x3e13, 0x2e32, 0x1e51, 0x0e70, 0xff9f, 0xefbe, 0xdfdd, 0xcffc, 0xbf1b, 0xaf3a, 0x9f59, 0x8f78, 0x9188, 0x81a9, 0xb1ca, 0xa1eb, 0xd10c, 0xc12d, 0xf14e, 0xe16f, 0x1080, 0x00a1, 0x30c2, 0x20e3, 0x5004, 0x4025, 0x7046, 0x6067, 0x83b9, 0x9398, 0xa3fb, 0xb3da, 0xc33d, 0xd31c, 0xe37f, 0xf35e, 0x02b1, 0x1290, 0x22f3, 0x32d2, 0x4235, 0x5214, 0x6277, 0x7256, 0xb5ea, 0xa5cb, 0x95a8, 0x8589, 0xf56e, 0xe54f, 0xd52c, 0xc50d, 0x34e2, 0x24c3, 0x14a0, 0x0481, 0x7466, 0x6447, 0x5424, 0x4405, 0xa7db, 0xb7fa, 0x8799, 0x97b8, 0xe75f, 0xf77e, 0xc71d, 0xd73c, 0x26d3, 0x36f2, 0x0691, 0x16b0, 0x6657, 0x7676, 0x4615, 0x5634, 0xd94c, 0xc96d, 0xf90e, 0xe92f, 0x99c8, 0x89e9, 0xb98a, 0xa9ab, 0x5844, 0x4865, 0x7806, 0x6827, 0x18c0, 0x08e1, 0x3882, 0x28a3, 0xcb7d, 0xdb5c, 0xeb3f, 0xfb1e, 0x8bf9, 0x9bd8, 0xabbb, 0xbb9a, 0x4a75, 0x5a54, 0x6a37, 0x7a16, 0x0af1, 0x1ad0, 0x2ab3, 0x3a92, 0xfd2e, 0xed0f, 0xdd6c, 0xcd4d, 0xbdaa, 0xad8b, 0x9de8, 0x8dc9, 0x7c26, 0x6c07, 0x5c64, 0x4c45, 0x3ca2, 0x2c83, 0x1ce0, 0x0cc1, 0xef1f, 0xff3e, 0xcf5d, 0xdf7c, 0xaf9b, 0xbfba, 0x8fd9, 0x9ff8, 0x6e17, 0x7e36, 0x4e55, 0x5e74, 0x2e93, 0x3eb2, 0x0ed1, 0x1ef0];

/**
 * @param {string} str
 * @returns {string}
 */
function computeCRC(str) {
  const bytes = Buffer.from(str, 'utf8');
  let crc = 0xffff;
  for (let i = 0; i < bytes.length; i++) {
    const c = bytes[i];
    const j = (c ^ crc >> 8) & 0xff;
    crc = CRC_TABLE[j] ^ crc << 8;
  }
  return ((crc ^ 0) & 0xffff).toString(16).toUpperCase().padStart(4, '0');
}

// ============================================================
// 2. Função auxiliar TLV (Tag-Length-Value)
// ============================================================
/**
 * @param {string} tag
 * @param {string | any[]} value
 * @returns {string}
 */
function tlv(tag, value) {
  const t = String(tag).padStart(2, '0');
  const l = String(value.length).padStart(2, '0');
  return `${t}${l}${value}`;
}

// ============================================================
// 3. Monta o payload BRCode do PIX Estático
// ============================================================

/**
 * Monta a string do payload BRCode para um PIX Estático.
 *
 * @param {Object} options - Dados do PIX
 * @param {string} options.chave
 * @param {string} options.merchantName
 * @param {string} options.merchantCity
 * @param {number} [options.transactionAmount]
 * @param {string} [options.txid]
 * @param {string} [options.infoAdicional]
 * @param {boolean} [options.oneTime]
 * @param {string} [options.merchantCategoryCode]
 * @param {number} [options.transactionCurrency]
 * @param {string} [options.countryCode]
 * @returns {string}
 */
function buildPixPayload({
  chave,
  merchantName,
  merchantCity,
  transactionAmount,
  txid = '***',
  infoAdicional,
  oneTime = false,
  merchantCategoryCode = '0000',
  transactionCurrency = 986,
  countryCode = 'BR'
}) {
  if (!chave) throw new Error('A chave PIX é obrigatória');
  if (!merchantName) throw new Error('O nome do recebedor é obrigatório');
  if (!merchantCity) throw new Error('A cidade do recebedor é obrigatória');
  const GUI_PIX = 'br.gov.bcb.pix';
  let payload = tlv('00', '01');
  if (oneTime) {
    payload += tlv('02', '12');
  }
  let maiContent = tlv('00', GUI_PIX);
  maiContent += tlv('01', chave);
  if (infoAdicional) {
    maiContent += tlv('02', infoAdicional);
  }
  payload += tlv('26', maiContent);
  payload += tlv('52', merchantCategoryCode);
  const currencyStr = String(transactionCurrency).padStart(3, '0');
  payload += tlv('53', currencyStr);
  if (transactionAmount !== undefined && transactionAmount !== null) {
    let amountStr = transactionAmount.toFixed(2);
    if (amountStr.endsWith('.00')) {
      amountStr = amountStr.slice(0, -3);
    }
    payload += tlv('54', amountStr);
  }
  payload += tlv('58', countryCode);
  payload += tlv('59', merchantName);
  payload += tlv('60', merchantCity);
  const additionalData = tlv('05', txid);
  payload += tlv('62', additionalData);
  payload += '6304';
  const crc = computeCRC(payload);
  payload += crc;
  return payload;
}

// ============================================================
// 4. Gerador do PIX Estático com QR Code
// ============================================================

/**
 * Gera o payload (BRCode) e a imagem do QR Code para um PIX Estático.
 * Retorna o mesmo formato do endpoint `pixGenerateQRCode` da API Efí:
 * `{ qrcode: string, imagemQrcode: string }`
 *
 * @param {Object} options - Dados do PIX
 * @param {string} options.chave - Chave PIX (CPF, CNPJ, e-mail, telefone ou chave aleatória)
 * @param {string} options.merchantName - Nome do recebedor (máx. 25 caracteres)
 * @param {string} options.merchantCity - Cidade do recebedor (máx. 15 caracteres)
 * @param {number} [options.transactionAmount] - Valor da transação (ex: 10.50). Opcional.
 * @param {string} [options.txid='***'] - Identificador da transação (máx. 25 caracteres)
 * @param {string} [options.infoAdicional] - Informação adicional no MAI do PIX
 * @param {boolean} [options.oneTime=false] - Se true, o QR Code é de pagamento único
 * @param {string} [options.merchantCategoryCode='0000'] - MCC
 * @param {number} [options.transactionCurrency=986] - Código da moeda (986 = BRL)
 * @param {string} [options.countryCode='BR'] - Código do país
 * @returns {Promise<{ qrcode: string, imagemQrcode: string }>}
 */
async function createStaticPix(options) {
  const payload = buildPixPayload(options);
  const svgString = await QRCode.toString(payload, {
    type: 'svg',
    errorCorrectionLevel: 'L',
    margin: 4
  });
  const svgBase64 = Buffer.from(svgString).toString('base64');
  const imagemQrcode = `data:image/svg+xml;base64,${svgBase64}`;
  return {
    qrcode: payload,
    imagemQrcode
  };
}

// @ts-nocheck
class EfiPay extends AllMethods {
  /**
   * Construtor da classe EfiPay.
   * @param {Object} options - Objeto com opções de configuração e credenciais.
   * @param {boolean} options.sandbox - Indica o ambite deseja, true para homologação e false para produção.
   * @param {string} options.client_id - Client ID obtido em sua conta.
   * @param {string} options.client_secret - Client Secrect obtido em sua conta.
   * @param {string} [options.partner_token] - Token de parceiro caso tenha.
   * @param {string} [options.certificate] - Caminho para o certificado
   * @param {boolean} [options.cert_base64] - Indica se será enviado o certificado em base64
   * @param {boolean} [options.validate_mtls] - Indica se será utilizado mTLS ou não no webhook
   * @param {boolean} [options.validateMtls] - Indica se será utilizado mTLS ou não no webhook 
   * @param {boolean} [options.cache] - Inidica se você deseja usar cache no token de autenticação, por padrão `true`
   * 
   * @param {string} [options.pix_cert] - # PRETERIDO # Caminho para o certificado
   * @param {string} [options.pemKey] - Caminho para a chave privada, caso opte por enviar o certificado em PEM.
  */
  constructor(options) {
    super();
    const self = this;
    if (options.cache === undefined) {
      options.cache = true;
    }
    if (options.pix_cert) {
      console.warn('⚠️  WARNING:\nO parâmetro "pix_cert" foi preterido, utilize "certificate" no lugar.');
      options.certificate = options.pix_cert;
    }
    let methods = {};
    Object.keys(constants.APIS).forEach(api => {
      Object.assign(methods, constants.APIS[api].ENDPOINTS);
    });
    let endpoints = new Endpoints(options, constants);
    Object.keys(methods).forEach(function (api) {
      self[api] = function (params, body) {
        return endpoints.run(api, params, body);
      };
    });
  }

  /**
   * Método para gerar o payload do PIX Estático e a imagem do QR Code em base64, retornando um objeto com os campos `qrcode` e `imagemQrcode`. O payload é gerado seguindo as especificações do Banco Central para o BRCode, incluindo a estrutura TLV e o cálculo do CRC-16 CCITT. A imagem do QR Code é gerada a partir do payload utilizando a biblioteca `qrcode`.
   * 
   * @param {Object} pixData
   * @param {string} pixData.chave - Chave PIX (CPF, CNPJ, e-mail, telefone ou chave aleatória)
   * @param {string} pixData.merchantName - Nome do recebedor (máx. 25 caracteres)
   * @param {string} pixData.merchantCity - Cidade do recebedor (máx. 15 caracteres)
   * @param {number} [pixData.transactionAmount] - Valor da transação (ex: 10.50). Opcional.
   * @param {string} [pixData.txid='***'] - Identificador da transação (máx. 25 caracteres)
   * @param {string} [pixData.infoAdicional] - Informação adicional no MAI do PIX
   * @param {boolean} [pixData.oneTime=false] - Se true, o QR Code é de pagamento único 
   * @returns {Promise<{ qrcode: string, imagemQrcode: string }>} - Retorna o payload do PIX e a imagem do QR Code em base64
   */
  async pixGenerateStaticQRCode(pixData) {
    return createStaticPix(pixData);
  }

  /**
   * Decodifica localmente um QR Code Pix dinâmico, sem chamada à API Efí.
   * O método extrai a URL do payload do BR Code, baixa o JWT e retorna apenas o payload decodificado.
   *
   * @param {{}} params
   * @param {{ pixCopiaECola: string }} body
   * @returns {Promise<{
   * 	tipoCob: 'cobv',
   *  calendario: {
   * 		criacao: string,
   * 		apresentacao: string,
   * 		dataDeVencimento: string,
   *      validadeAposVencimento: number
   * 	},
   *  devedor: {nome: string, cpf: string, email?: string, logradouro?: string, cidade?: string, uf?: string, cep?: string} | {nome: string, cnpj: string, email?: string, logradouro?: string, cidade?: string, uf?: string, cep?: string} 
   *  recebedor: {nome: string, cnpj: string, logradouro: string, cidade: string, uf: string, cep: string} | {nome: string, cpf: string, logradouro: string, cidade: string, uf: string, cep: string}
   *  txid: string,
   *  status: 'ATIVA' | 'CONCLUIDA' | 'REMOVIDA_PELO_PSP' | 'REMOVIDA_PELO_USUARIO',
   *  revisao: number,
   *  valor: {original?: string, juros?: string, multa?: string, desconto?: string, abatimento?: string, final: string}, 
   *  chave: string,
   *  solicitacaoPagador?: string,
   *  infoAdicionais?: {nome: string, valor: string}[],
   * } 
   * | 
   * {
   * 	tipoCob: 'cob',
   *  calendario: {
   * 		criacao: string,
   * 		apresentacao: string,
   * 		expiracao: string,
   * 	},
   *  devedor: {nome: string, cpf: string} | {nome: string, cnpj: string} 
   *  recebedor: {nome: string, cnpj: string} | {nome: string, cpf: string}
   *  txid: string,
   *  status: 'ATIVA' | 'CONCLUIDA' | 'REMOVIDA_PELO_PSP' | 'REMOVIDA_PELO_USUARIO',
   *  revisao: number,
   *  valor: {final: string}, 
   *  chave: string,
   *  solicitacaoPagador?: string,
   *  infoAdicionais?: {nome: string, valor: string}[],
   * }
   * | 
   * string>}
   */
  async pixQrCodeDetail(params, body) {
    if (!body || typeof body.pixCopiaECola !== 'string' || body.pixCopiaECola.trim() === '') {
      throw new Error('O campo "pixCopiaECola" é obrigatório e deve ser uma string.');
    }
    const decoded = await getDecodedPixJwt(body.pixCopiaECola);
    const tipoCob = body.pixCopiaECola.includes('/cobv/') ? 'cobv' : 'cob';
    return {
      tipoCob,
      ...decoded.payload
    };
  }
}

export { EfiPay as default };
